Here is a batch script that generates two random variables and writes them into a JSON file named output.json:

@echo off

REM Generate random variables
set /a var1=%RANDOM%
set /a var2=%RANDOM%

REM Write variables to JSON file
(
  echo { 
  echo "variable1": %var1%, 
  echo "variable2": %var2% 
  echo }
) > output.json

echo JSON data has been written to output.json.
